import{_ as e,p as a,q as l,a1 as t}from"./framework-204010b2.js";const i={},r=t('<h3 id="什么是网页" tabindex="-1"><a class="header-anchor" href="#什么是网页" aria-hidden="true">#</a> 什么是网页？</h3><ol><li>网站是指在因特网上根据一定的规则，使用HTML等制作的用于展示特定内容相关的网页集合。</li><li>网页是网站中的一“页”，通常是HTML格式的文件，它要通过浏览器来阅读。</li><li>网页是构成网站的基本元素，它通常由图片、链接、文字、声音、视频等元素组成。通常我们看到的网页，常见以.htm 或.html后缀结尾的文件，因此将其俗称为HTML文件。</li></ol><h3 id="什么是html" tabindex="-1"><a class="header-anchor" href="#什么是html" aria-hidden="true">#</a> 什么是html？</h3><ol><li>HTML指的是超文本标记语言(Hyper Text Markup Language)，它是用来描述网页的一种语言。</li><li>HTML不是一种编程语言，而是一种标记语言(markup language)。</li><li>标记语言是一套标记标签(markup tag)。</li></ol>',4),n=[r];function h(o,c){return a(),l("div",null,n)}const s=e(i,[["render",h],["__file","index.html.vue"]]);export{s as default};
